steps.script:
var f = tree.root.gui_get_focus_owner()
if f == null:
	return "no focus"
if f is ItemList:
	return "MISFIRE: itemlist"
return "button:" + str(f.name)

var fc = tree.current_scene.fight_controller
var btn = null
var q = [fc.pile_in_step_panel]
while not q.is_empty():
	var n = q.pop_front()
	if n is Button and str(n.name) == "PileIn_U_WARBOSS_B":
		btn = n
	for c in n.get_children():
		q.append(c)
if btn == null:
	return "no button"
btn.grab_focus()
return str(tree.root.gui_get_focus_owner().name)

var d = tree.root.get_node_or_null("PileInDialog")
var h = d.get_node_or_null("Content/PadHintLabel")
return h != null and h.visible
